"use client";
import Link from "next/link";
import Image from "next/image";
import styles from "./page.module.scss";
import HomeHeader from "@/components/HomeHeader/index";
import HomeFooter from "@/components/HomeFooter/index";
import { useState, useEffect, useCallback } from "react";

const images = ["/qc1.webp", "/qc2.jpg", "/qc3.jpg", "/qc4.jpg"];
import comment from "@/app/assets/images/comment.svg"; // Correct import statement

export default function Home() {
  const [currentImageIndex, setCurrentImageIndex] = useState(0);
  const [isMouseOver, setIsMouseOver] = useState(false);
  const [showBackToTop, setShowBackToTop] = useState(false);
  const [showSupport, setShowSupport] = useState(false);
  //Remove this so it hovers directly instead of only clicking it.
  // const [showSupportOptions, setShowSupportOptions] = useState(false);
  //Just adding supportHover instead
  const [supportHover, setSupportHover] = useState(false);

  const goToPrevious = useCallback(() => {
    setCurrentImageIndex((prevIndex) =>
      prevIndex === 0 ? images.length - 1 : prevIndex - 1
    );
  }, [images.length]);

  const goToNext = useCallback(() => {
    setCurrentImageIndex((prevIndex) =>
      prevIndex === images.length - 1 ? 0 : prevIndex + 1
    );
  }, [images.length]);

  useEffect(() => {
    let intervalId: NodeJS.Timeout | null = null;
    if (!isMouseOver) {
      intervalId = setInterval(() => {
        goToNext();
      }, 5000);
    }

    return () => {
      if (intervalId) {
        clearInterval(intervalId);
      }
    };
  }, [goToNext, isMouseOver]);

  useEffect(() => {
    const handleScroll = () => {
      const scrollPosition =
        document.body.scrollTop || document.documentElement.scrollTop;
      setShowBackToTop(scrollPosition > 20);
      setShowSupport(scrollPosition > 20);
    };

    window.addEventListener("scroll", handleScroll);

    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  const backToTop = () => {
    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  //REMOVE THIS toggle because we are no longer clicking to open.
  // const toggleSupportOptions = () => {
  //   setShowSupportOptions((prevState) => !prevState);
  // };

  return (
    <>
      <HomeHeader />

      {showBackToTop && (
        <button
          className={styles.backToTopBtn}
          onClick={backToTop}
          title="Go to top"
        >
          <Image src="/MuiTen.webp" alt="Mũi tên lên" width={30} height={30} />
        </button>
      )}

      {showSupport && (
        <button
          className={styles.supportButton}
          //Add a hoover state
          onMouseEnter={() => setSupportHover(true)}
          onMouseLeave={() => setSupportHover(false)}
        >
          <Image src={comment} alt="Hỗ Trợ" width={30} height={30} /> hỗ trợ?
        </button>
      )}

      {/*Use the new hover State*/}
      {supportHover && (
        <div className={styles.supportOptions}>
          <button
            className={styles.closeSupportOptions}
            //Remove the event listener to disable clicking.
            // onClick={toggleSupportOptions}
            //This makes the component disappear immediately
            onMouseLeave={() => setSupportHover(false)}
          ></button>
          <a href="#">
            <i className="fab fa-facebook"></i> Facebook
          </a>
          <a href="#">
            <i className="fas fa-phone"></i> Điện thoại
          </a>
          <a href="#">
            <i className="fab fa-youtube"></i> YouTube
          </a>
          <a href="#">
            <i className="fab fa-instagram"></i> Instagram
          </a>
          <a href="#">
            <i className="fab fa-twitter"></i> Twitter
          </a>
          <a href="#">
            <i className="fab fa-linkedin"></i> LinkedIn
          </a>
          <a href="#">
            <i className="fab fa-telegram"></i> Telegram
          </a>
          <a href="#">
            <i className="fab fa-whatsapp"></i> WhatsApp
          </a>
          <a href="#">
            <i className="fab fa-discord"></i> Discord
          </a>
        </div>
      )}

      <div
        className={styles.carouselContainer}
        onMouseEnter={() => setIsMouseOver(true)}
        onMouseLeave={() => setIsMouseOver(false)}
      >
        <button className={styles.carouselButton} onClick={goToPrevious}>
          Trai
        </button>
        <Image
          src={images[currentImageIndex]}
          alt={`Carousel Image ${currentImageIndex + 1}`}
          width={1200}
          height={400}
          style={{ objectFit: "cover" }}
          priority={true}
        />
        <button className={styles.carouselButton} onClick={goToNext}>
          Phai
        </button>
      </div>

      <HomeFooter />
    </>
  );
}
